o=A.hy(A.b([A.cn("The city's definitive sunset rampart.","9 km from Jaipur","Nahargarh Fort"),A.cn("Chand Baori's thirteen-storey geometry.","88 km from Jaipur","Abhaneri stepwell"),A.cn("Flamingos and salt flats shot straight from a dream.","80 km from Jaipur","Sambhar salt lake")],i2),e8,h9,d,4,h8,!0,k,m,n,j,"d09",h1,l,26.9124,75.7873,"Jaipur",3,"Jaipur is theatre \u2014 Amber Fort's mirrored halls, the honeycomb of Hawa Mahal, bazaars dense with gemstones and block print. We open its quieter doors: private palace dinners, textile ateliers with master printers, dawn at Amber before the gates, and a hot-air balloon drifting over the Aravallis.",21900,4.8,1195,A.b([A.dC("Charlotte Dubois","The balloon at dawn over Amber \u2014 I have no words that do it justice.",e6,"Paris",5),A.dC("Nikhil Choudhary","I grew up here and they still showed me rooms I'd never seen.",b5,"Jaipur",4.7)],i3),"Historian-led forts, balloon flights and haveli stays in the pink city.","Jaipur Royal Journeys \u2014 Amber at Dawn & Palace Dinners","jaipur","The pink city, palace doors ajar",o,a3)
